@RequestMapping("/api/webhook")
class WebhookController {

    private final HttpClient httpClient;
    private final UrlValidator urlValidator;

    private static final int MAX_REDIRECTS = 0; // No redirects allowed
    private static final int MAX_RESPONSE_SIZE = 1024 * 1024; // 1MB max response
    private static final Duration REQUEST_TIMEOUT = Duration.ofSeconds(15);

    public WebhookController(HttpClient httpClient, UrlValidator urlValidator) {
        this.httpClient = httpClient;
        this.urlValidator = urlValidator;
    }

    @PostMapping("/process")
    public ResponseEntity<WebhookResponse> processWebhook(@RequestBody WebhookRequest request) {
        // Validate the incoming request
        if (request == null || request.getCallbackUrl() == null) {
            return ResponseEntity.badRequest()
                    .body(new WebhookResponse("error", "Missing callback URL", null));
        }

        URI validatedUri;
        try {
            // SSRF Protection: Validate URL before making any request
            validatedUri = urlValidator.validate(request.getCallbackUrl());
        } catch (IllegalArgumentException e) {
            return ResponseEntity.badRequest()
                    .body(new WebhookResponse("error", "Invalid URL: " + e.getMessage(), null));
        }

        try {
            String content = fetchContent(validatedUri);
            return ResponseEntity.ok(
                    new WebhookResponse("success", "Content fetched successfully", content));
        } catch (IOException | InterruptedException e) {
            Thread.currentThread().interrupt();
            return ResponseEntity.status(HttpStatus.BAD_GATEWAY)
                    .body(new WebhookResponse("error", "Failed to fetch content: " + e.getMessage(), null));
        } catch (SecurityException e) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN)
                    .body(new WebhookResponse("error", "Security violation: " + e.getMessage(), null));
        }
    }

    private String fetchContent(URI uri) throws IOException, InterruptedException {
        HttpRequest request = HttpRequest.newBuilder()
                .uri(uri)
                .timeout(REQUEST_TIMEOUT)
                .header("User-Agent", "WebhookHandler/1.0")
                .header("Accept", "application/json, text/plain")
                .GET()
                .build();

        HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());

        int statusCode = response.statusCode();

        // Reject redirects - we configured HttpClient with NEVER redirect policy,
        // but double-check here
        if (statusCode >= 300 && statusCode < 400) {
            throw new SecurityException("Redirects are not allowed. Server returned status: " + statusCode);
        }

        if (statusCode < 200 || statusCode >= 300) {
            throw new IOException("Upstream server returned error status: " + statusCode);
        }

        String body = response.body();
        if (body != null && body.length() > MAX_RESPONSE_SIZE) {
            throw new IOException("Response exceeds maximum allowed size of " + MAX_RESPONSE_SIZE + " bytes");
        }

        return body;
    }
}

